    async findAllWallets(): Promise<IWallet[]> {
        return await Wallet.find()
            .populate('mentorId', 'name email')
            .populate('userId', 'name email');
    }

    async getGlobalTransactions(
        page: number,
        limit: number,
        filter: 'all' | 'mentor' | 'user'
    ): Promise<{ transactions: ITransaction[]; total: number }> {
        const match: Record<string, unknown> = {};
        if (filter === 'mentor') match.mentorId = { $exists: true };
        if (filter === 'user') match.userId = { $exists: true };

        const pipeline: PipelineStage[] = [
            { $match: match },
            { $unwind: '$transactions' },
            { $sort: { 'transactions.date': -1 } },
            {
                $lookup: {
                    from: 'users',
                    localField: 'userId',
                    foreignField: '_id',
                    as: 'userDetails',
                },
            },
            {
                $lookup: {
                    from: 'mentors',
                    localField: 'mentorId',
                    foreignField: '_id',
                    as: 'mentorDetails',
                },
            },
            {
                $project: {
                    _id: 0,
                    walletId: '$_id',
                    transactionId: '$transactions._id',
                    amount: '$transactions.amount',
                    type: '$transactions.type',
                    status: '$transactions.status',
                    description: '$transactions.description',
                    date: '$transactions.date',
                    referenceId: '$transactions.referenceId',
                    user: {
                        name: { $arrayElemAt: ['$userDetails.name', 0] },
                        email: { $arrayElemAt: ['$userDetails.email', 0] },
                    },
                    mentor: {
                        name: { $arrayElemAt: ['$mentorDetails.name', 0] },
                        email: { $arrayElemAt: ['$mentorDetails.email', 0] },
                    },
                    bankAccountDetails: '$bankAccountDetails',
                    stripeConnectAccountId: '$stripeConnectAccountId',
                    stripeConnectOnboarded: '$stripeConnectOnboarded',
                },
            },
            {
                $facet: {
                    metadata: [{ $count: 'total' }],
                    data: [{ $skip: (page - 1) * limit }, { $limit: limit }],
                },
            },
        ];

        const result = await this.model.aggregate(pipeline);
        const data = result[0].data as ITransaction[];
        const total = result[0].metadata[0]?.total || 0;

        return { transactions: data, total };
    }

    async findPaginatedTransactions(
        walletId: string | ObjectId,
        page: number,
        limit: number
    ): Promise<{ transactions: ITransaction[]; total: number }> {
        const pipeline: PipelineStage[] = [
            {
                $match: {
                    _id: new Wallet.base.Types.ObjectId(walletId.toString()),
                },
            },
            { $unwind: '$transactions' },
            { $sort: { 'transactions.date': -1 } },
            {
                $facet: {
                    metadata: [{ $count: 'total' }],
                    data: [{ $skip: (page - 1) * limit }, { $limit: limit }],
                },
            },
        ];

        const result = await Wallet.aggregate(pipeline);
        const data = result[0].data.map(
            (item: { transactions: ITransaction }) => item.transactions
        );
        const total = result[0].metadata[0]?.total || 0;

        return { transactions: data, total };
    }

    async updateStripeConnectId(
        mentorId: string,
        accountId: string
    ): Promise<void> {
        await this.model.updateOne(
            { mentorId: mentorId },
            { $set: { stripeConnectAccountId: accountId } }
        );
    }

    async updateWallet(walletId: string, wallet: WalletEntity): Promise<void> {
        const persistence = WalletMapper.ToPersistence(wallet);
        await this.update(walletId, persistence);
    }
